import{c as a,Q as r,j as t,m as l}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Keep Agentic AI Simple: A Practical Workflow for Software Development","description":"","frontmatter":{"url":"https://timdeschryver.dev/blog/keep-agentic-ai-simple-a-practical-workflow-for-software-development","title":"Keep Agentic AI Simple: A Practical Workflow for Software Development","type":"article"},"headers":[],"relativePath":"research/ai-articles/16-timdeschryver-keep-agentic-simple.md","filePath":"research/ai-articles/16-timdeschryver-keep-agentic-simple.md","lastUpdated":1779796674000}'),i={name:"research/ai-articles/16-timdeschryver-keep-agentic-simple.md"};function o(s,e,n,c,p,h){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="keep-agentic-ai-simple-a-practical-workflow-for-software-development" tabindex="-1">Keep Agentic AI Simple: A Practical Workflow for Software Development <a class="header-anchor" href="#keep-agentic-ai-simple-a-practical-workflow-for-software-development" aria-label="Permalink to &quot;Keep Agentic AI Simple: A Practical Workflow for Software Development&quot;">​</a></h1><p><strong>原始 URL</strong>: <a href="https://timdeschryver.dev/blog/keep-agentic-ai-simple-a-practical-workflow-for-software-development" target="_blank" rel="noreferrer">https://timdeschryver.dev/blog/keep-agentic-ai-simple-a-practical-workflow-for-software-development</a></p><p><strong>作者</strong>: Tim Deschryver<br><strong>修改日期</strong>: 2026 年 5 月 7 日</p><hr><h2 id="核心摘要" tabindex="-1">核心摘要 <a class="header-anchor" href="#核心摘要" aria-label="Permalink to &quot;核心摘要&quot;">​</a></h2><p>Tim Deschryver 分享了他使用 AI 代理重寫專案的經驗，他將自己定位為團隊領導者，同時把 AI 視為「侍從」（自行車賽中的支援騎手）。此篇強調了思慮周詳的架構和策略性監督，而不是依賴快速修復。</p><p>該方法論代表了軟體工程的根本轉變：從關注技術細節轉向提供良好的「護欄」（guardrails），讓 AI 代理能有效執行工作。核心理念是開發者的角色變得更少涉及技術細節，更多是架構層級的思考與把關。</p><h3 id="三個核心實踐組件" tabindex="-1">三個核心實踐組件 <a class="header-anchor" href="#三個核心實踐組件" aria-label="Permalink to &quot;三個核心實踐組件&quot;">​</a></h3><ol><li><strong>AGENTS.md 文件</strong> — 標準化指令文件，包含專案結構、技術棧、命令、編碼慣例與資料庫圖表，應定期審查以保持準確並累積錯誤模式</li><li><strong>Agent Skills</strong> — Markdown 知識檔案擴展 AI 能力，與 AGENTS.md 的區別在於 skills 僅在相關時載入</li><li><strong>規格驅動開發</strong> — 使用 OpenSpec 在實作前生成提案、設計和任務文件，分解工作為可管理的步驟</li></ol><hr><h2 id="關鍵實踐" tabindex="-1">關鍵實踐 <a class="header-anchor" href="#關鍵實踐" aria-label="Permalink to &quot;關鍵實踐&quot;">​</a></h2><h3 id="agents-md-的角色" tabindex="-1">AGENTS.md 的角色 <a class="header-anchor" href="#agents-md-的角色" aria-label="Permalink to &quot;AGENTS.md 的角色&quot;">​</a></h3><p>此檔案成為 AI 代理的「憲法」，提供一致的框架。內容涵蓋：</p><ul><li>專案結構與技術棧</li><li>重複的命令與编碼慣例</li><li>資料庫設計圖表</li><li>防止 AI 遺漏微妙要求的清單</li></ul><h3 id="agent-skills-系統" tabindex="-1">Agent Skills 系統 <a class="header-anchor" href="#agent-skills-系統" aria-label="Permalink to &quot;Agent Skills 系統&quot;">​</a></h3><p>區分於 AGENTS.md（總是包含），skills 文件採用按需載入模式。Deschryver 結合官方 Angular 和 .NET skills 加上自定義設計系統 skills，確保視覺與代碼一致性。</p><h3 id="規格驅動開發流程" tabindex="-1">規格驅動開發流程 <a class="header-anchor" href="#規格驅動開發流程" aria-label="Permalink to &quot;規格驅動開發流程&quot;">​</a></h3><p>在實作前使用 OpenSpec 生成規範文件，將工作分解為明確步驟，防止 AI 遺漏邊界情況。</p><h3 id="工具與模型選擇" tabindex="-1">工具與模型選擇 <a class="header-anchor" href="#工具與模型選擇" aria-label="Permalink to &quot;工具與模型選擇&quot;">​</a></h3><p>作者發現 Claude 與 Codex 同樣有用，因快速迭代模型改進。偏好 OpenCode 以避免供應商鎖定。</p><hr><h2 id="關鍵引用與數據" tabindex="-1">關鍵引用與數據 <a class="header-anchor" href="#關鍵引用與數據" aria-label="Permalink to &quot;關鍵引用與數據&quot;">​</a></h2><blockquote><p>「不要做害怕 AI 的開發者。要做學會把它視為最新系統的開發者。」— Tim Deschryver</p></blockquote><blockquote><p>「我們作為軟體工程師的角色變得更少技術細節，更多是提供良好護欄讓代理工作。」</p></blockquote><p><strong>核心轉變</strong>: 從微管理實作細節轉向架構層級思考與品質把關。</p><hr><h2 id="工作流程的實踐意義" tabindex="-1">工作流程的實踐意義 <a class="header-anchor" href="#工作流程的實踐意義" aria-label="Permalink to &quot;工作流程的實踐意義&quot;">​</a></h2><p>此方法適用於不同規模的團隊，強調：</p><ul><li>清晰的指令文件優於逐次對話重複指示</li><li>規格驅動減少返工與需求遺漏</li><li>開發者角色提升至戰略層級</li><li>AI 作為可靠的執行工具，而非決策者</li></ul><p>Deschryver 的實踐展現了人類開發者與 AI 協作的新模式：領導力來自架構設計與需求管理，執行由 AI 承擔。</p>',30)])])}const f=a(i,[["render",o]]);export{m as __pageData,f as default};
